def solve(inputs):
    # Validate inputs vs contract
    if not isinstance(inputs, dict):
        raise ValueError("Input must be a dictionary")

    required_keys = ['sequence', 'quality']
    for key in required_keys:
        if key not in inputs:
            raise ValueError(f"Missing required input: {key}")

    sequence = inputs['sequence']
    quality = inputs['quality']

    # Implement core logic
    if not isinstance(sequence, str) or not isinstance(quality, list):
        raise ValueError("Invalid types for sequence or quality")

    if len(sequence) != len(quality):
        raise ValueError("Length of sequence and quality must match")

    # Example QC logic: Check for valid nucleotide characters and quality scores
    valid_nucleotides = {'A', 'C', 'G', 'T'}
    for nucleotide in sequence:
        if nucleotide not in valid_nucleotides:
            raise ValueError(f"Invalid nucleotide found: {nucleotide}")

    for score in quality:
        if not (0 <= score <= 40):
            raise ValueError(f"Quality score out of range: {score}")

    # Return a simple QC report
    return {
        "valid_sequence": True,
        "valid_quality": True,
        "length": len(sequence)
    }
